/**
 * @module PlayerConstants
 * @description Core constants used throughout the Cadmium player, including
 * codec MIME types, DRM system IDs, MP4 box identifiers, time conversion
 * factors, buffer size limits, base64-encoded init segment headers for
 * various video codecs (AVC, HEVC, Dolby Vision), and pre-built encrypted
 * stream headers used for MSE initialization.
 * @origin Module_33096
 */

// ─── Utility functions ──────────────────────────────────────────────────────

/** No-op function */
export function noop() {}

/** Always returns true */
export function alwaysTrue() {
  return true;
}

// ─── Success sentinel ───────────────────────────────────────────────────────

/** Standard success result object */
export const SUCCESS = { success: true };

// ─── Time / size constants ──────────────────────────────────────────────────

/** Milliseconds per second */
export const segmentDurationMs = 1000;

/** Seconds in one day */
export const SECONDS_PER_DAY = 86400;

/** Seconds in one week */
export const SECONDS_PER_WEEK = 604800;

/** 10,000 (used for HNS tick conversions) */
export const HNS_TICKS_10K = 10000;

/** 10,000,000 (hundred-nanosecond ticks per second) */
export const HNS_TICKS_PER_SECOND = 10000000;

/** Ratio constant 1.5 */
export const BUFFER_RATIO = 1.5;

/** 0.128 constant */
export const SMALL_BUFFER_THRESHOLD = 0.128;

/** 7.8125 constant */
export const FREQUENCY_CONSTANT = 7.8125;

/** 128 byte block size */
export const BLOCK_SIZE = 128;

/** Large time value in ms (145,152,000,000 ms ~ 4.6 years) */
export const MAX_DURATION_MS = 145152e5;

/** 100,000 constant */
export const LARGE_SEGMENT_THRESHOLD = 100000;

// ─── Player ordering ────────────────────────────────────────────────────────

/** Storage key for player instance ordering */
export const PLAYER_ORDER_KEY = '$netflix$player$order';

/** Sentinel for unset / default index */
export const UNSET_INDEX = -1;

/** Initial index value */
export const INITIAL_INDEX = 1;

// ─── Locale / encoding ──────────────────────────────────────────────────────

/** Default locale fallback */
export const DEFAULT_LOCALE = ['en-US'];

/** Bits per byte */
export const BITS_PER_BYTE = 8;

/** Max 16-bit unsigned value */
export const MAX_UINT16 = 65535;

/** 2^16 */
export const UINT16_OVERFLOW = 65536;

/** Max safe number value */
export const MAX_NUMBER = Number.MAX_VALUE;

// ─── DRM systems ────────────────────────────────────────────────────────────

/** PlayReady DRM system identifier */
export const DRM_PLAYREADY = 'playready';

/** Widevine DRM system identifier */
export const DRM_WIDEVINE = 'widevine';

/** FairPlay Streaming DRM system identifier */
export const DRM_FAIRPLAY = 'fps';

