// ─── Pre-built encrypted init segment headers (base64) ──────────────────────
// These are complete ftyp+moov MP4 init segments with PSSH boxes for
// PlayReady, Widevine and Marlin DRM systems, used to "prime" the
// SourceBuffer so that it can accept both clear and encrypted content.

/** Encrypted header for AVC (H.264) content */
export const ENCRYPTED_HEADER_AVC = '';

/** Encrypted header for HEVC (H.265 / Main10) content */
export const ENCRYPTED_HEADER_HEVC = '';

/** Encrypted header for Dolby Vision (dvhe) content */
export const ENCRYPTED_HEADER_DV = '';

/** Encrypted header for Dolby Vision (GPAC 2.2.1 variant) content */
export const ENCRYPTED_HEADER_DV_V2 = '';

/** Encrypted header for AAC audio content */
export const ENCRYPTED_HEADER_AAC = '';
